def predict_next_frame(frame, action, xy=None):
    """
    Predicts the next frame for the 64x64 grid game.

    Observed rules:
      * ACTION1 clears cell (63, 60).
      * ACTION2 clears cells (63, 6) and (63, 7).
      * ACTION4 clears cells (63, 56) and (63, 57).
      * ACTION3 clears a 3×3 block that matches the pattern:
            left column values are 2,
            right column values are 9 except the middle row right value is 4,
            and also clears cells (63, 56) and (63, 57).
    All other actions leave the frame unchanged.
    """
    # Deep copy to avoid mutating the input
    new_frame = [row[:] for row in frame]

    if action == "ACTION1":
        if new_frame[63][60] == 6:
            new_frame[63][60] = 0

    elif action == "ACTION2":
        for col in (6, 7):
            if new_frame[63][col] == 6:
                new_frame[63][col] = 0

    elif action == "ACTION4":
        for col in (56, 57):
            if new_frame[63][col] == 6:
                new_frame[63][col] = 0

    elif action == "ACTION3":
        # Clear the bottom row cells 56 and 57
        for col in (56, 57):
            if new_frame[63][col] == 6:
                new_frame[63][col] = 0

        # Search for the 3×3 pattern
        for r in range(0, 61):          # 61 = 64-3
            for c in range(0, 61):
                # Check left column values
                if not (new_frame[r][c] == 2 and
                        new_frame[r+1][c] == 2 and
                        new_frame[r+2][c] == 2):
                    continue
                # Check right column values
                if not (new_frame[r][c+3] == 9 and
                        new_frame[r+1][c+3] == 4 and
                        new_frame[r+2][c+3] == 9):
                    continue
                # Pattern matched – clear the 3×3 block
                for dr in range(3):
                    for dc in range(4):
                        if new_frame[r+dr][c+dc] != 0:
                            new_frame[r+dr][c+dc] = 0
                # Assume only one such block per ACTION3
                return new_frame

    # For all other actions, return the frame unchanged
    return new_frame
